const toMinutes = (time: string): number => {
  const [hrs, mins] = time.split("h");
  return Number(hrs) * 60 + Number(mins);
};

const sleep = (n: number) => {
  if (n < 4 * 90) return "Lack of sleep";
  else if (4 * 90 <= n && n <= 6 * 90) return "Perfect sleep";
  return "Too much sleep";
};

const timing = (n: number) => {
  const left = n % 90;
  if (left === 0) return "Perfect timing";
  else if (left < 30) return "Decent timing";
  return "Bad timing";
};

/**
 * Always of the format: [0-9]{2}h[0-9]{2}
 */
const t: string = readline();
const minutes = toMinutes(t);

console.log(`${sleep(minutes)}, ${timing(minutes)}`);
